            "Tool8_id", "Tool8_status", "SMTP8_result", "SMTP8_dt",
            "Final_status", "EBB_team", "Autoupload_dt", "Uploaded_dt", "Uploaded_by", "Isdelete", "Isverificationtermexpired"
        ],
    },
    {
        title: "tblsmtpaudit_details_v3",
        key: "tblsmtpaudit_details_v3",
        headers: [
            "Record ID", "I Date", "Client ID", "Email ID", "Reason Code",
