            "Tool6 ID", "Tool6 Status", "SMTP6 Result", "SMTP6 Dt",
            "Tool7 ID", "Tool7 Status", "SMTP7 Result", "SMTP7 Dt",
            "Tool8 ID", "Tool8 Status", "SMTP8 Result", "SMTP8 Dt",
            "Final Status", "EBB Team", "Autoupload Dt", "Uploaded Dt", "Uploaded By", "Is Delete", "Is Verification Term Expired"
        ],
        fields: [
            "Record_id", "iDate", "Client_id", "Email_id", "Reason_code",
            "Tool1_id", "Tool1_status", "SMTP1_result", "SMTP1_dt",
            "Tool2_id", "Tool2_status", "SMTP2_result", "SMTP2_dt",
