            "Final_status", "EBB_team", "Autoupload_dt", "Uploaded_dt", "Uploaded_by", "Isdelete", "Isverificationtermexpired"
        ],
    },
    {
        title: "tblleads_masterlist_tracker",
        key: "tblleads_masterlist_tracker",
        headers: [
            "Track ID", "Lead ID", "Mail Domain", "Company Name", "Industry", "Standard Industry ID",
            "Industry Type Link", "SIC Code", "NAICS Code", "SIC/NAICS Link", "Employee Size ID", "Actual Employee Size",
