            "Country_id", "State_id", "City_id", "Zip_code", "Salutation_id", "First_name", "Last_name", "Country_code",
            "Phone_number", "Mobile_No", "Direct_dial_extension", "Email_id", "Job_title", "Job_title_link", "Tenurity",
            "Tenurity_link", "Job_level_id", "Jobfunction_id", "Timezone_abbr", "IsMISupload", "Isuserupload",
            "Uploaded_dt", "Uploaded_by", "Edited_dt", "Edited_by", "Isdelete", "Contact_success_attempts",
            "Datareuse_asis_until_dt"
        ],
    },
];

// 🔹 Reusable Table Component
const DataTable = ({ title, headers, rows, fields }) => (
    <div className="card mb-4 shadow-sm">
        <div className="card-header bg-dark text-white">{`Table: ${title}`}</div>
        <div className="card-body p-0">
            <div className="table-responsive">
                {rows?.length > 0 ? (
                    <table className="table table-bordered table-hover">
                        <thead className="table-dark">
                            <tr>{headers.map((h, i) => <th key={i}>{h}</th>)}</tr>
                        </thead>
                        <tbody>
                            {rows.map((row, i) => (
                                <tr key={i}>
                                    {fields.map((f, j) => <td key={j}>{row[f]}</td>)}
                                </tr>
                            ))}
                        </tbody>
                    </table>
                ) : (
                    <p className="p-2">No rows found.</p>
                )}
            </div>
        </div>
    </div>
);

function Leads() {
    const [data, setData] = useState({});
    const [selectedRole, setSelectedRole] = useState("super_admin");
    const [showDecrypted, setShowDecrypted] = useState(false);

    useEffect(() => {
        const fetchLeads = async () => {
            try {
                const res = await axios.get("http://172.16.60.17:8000/leads", {
                    params: { role: selectedRole, decrypted: showDecrypted ? 1 : 0 },
                });
                setData(res.data);
            } catch (error) {
                console.error("Error fetching leads:", error);
                setData({});
            }
        };
        fetchLeads();
    }, [selectedRole, showDecrypted]);

    return (
        <div className="container mt-4">
            {/* Role + Toggle */}
            <div className="d-flex justify-content-between align-items-center mb-4">
                <select
                    className="form-select w-auto"
                    value={selectedRole}
                    onChange={(e) => setSelectedRole(e.target.value)}
                >
                    <option value="super_admin">Super Admin</option>
                    <option value="admin">Admin</option>
                    <option value="agent">Agent</option>
                </select>
                <button
                    className="btn btn-primary btn-sm"
                    onClick={() => setShowDecrypted((prev) => !prev)}
                    disabled={selectedRole === "agent"}
                >
                    {showDecrypted ? "🔒 Show Encrypted" : "🔑 Show Decrypted"}
                </button>
            </div>

            {/* Render All Tables */}
            {tablesConfig.map((tbl, i) => (
                <DataTable
                    key={i}
                    title={tbl.title}
                    headers={tbl.headers}
                    fields={tbl.fields}
                    rows={data[tbl.key]}
                />
            ))}
        </div>
    );
}

export default Leads;
